let body = $json.body ?? $json;
if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch {
    throw new Error('Invalid JSON in webhook body');
  }
}

const topic = body.topic?.toString().trim();
if (!topic) {
  throw new Error('Missing required field: topic');
}

const audience = body.audience?.toString().trim() || 'Software engineers and product builders';
const tone = body.tone?.toString().trim() || 'Practical, insightful, and actionable';
const wordCount = Number(body.wordCount ?? 1400);
const cta = body.cta?.toString().trim() || 'Try building one workflow this week and measure results.';

return [{
  json: {
    topic,
    audience,
    tone,
    wordCount: Number.isFinite(wordCount) ? Math.max(700, Math.min(3000, wordCount)) : 1400,
    cta,
    requestedAt: new Date().toISOString()
  }
}];

const topic = $json.topic;
const audience = $json.audience;
const tone = $json.tone;
const wordCount = Number($json.wordCount ?? 1400);

const searchQueries = [
  `${topic}`,
  `${topic} tutorial`,
  `${topic} examples`,
  `${topic} best practices`,
  `${topic} implementation guide`
];

const outline = [
  {
    section: 'Introduction',
    bullets: [
      `Explain why ${topic} matters now`,
      `Frame the problem for ${audience}`
    ]
  },
  {
    section: 'Core Concepts',
    bullets: [
      `Define the main building blocks behind ${topic}`,
      'Clarify terminology and trade-offs',
      'Show where teams usually get stuck'
    ]
  },
  {
    section: 'Implementation Walkthrough',
    bullets: [
      'Break the workflow into concrete steps',
      'Include architecture, tooling, and handoff points',
      'Call out validation and failure handling'
    ]
  },
  {
    section: 'Practical Example',
    bullets: [
      `Give a realistic example centered on ${topic}`,
      'Show inputs, outputs, and expected behavior'
    ]
  },
  {
    section: 'Best Practices',
    bullets: [
      'Cover observability, retries, and guardrails',
      'Mention cost, performance, and maintainability'
    ]
  },
  {
    section: 'Conclusion',
    bullets: [
      'Summarize the key implementation lessons',
      'End with a practical next step'
    ]
  }
];

const angle = `${tone} guide for ${audience} with a strong implementation focus and a target length of about ${wordCount} words.`;

return [{
  json: {
    search_queries: searchQueries,
    angle,
    outline,
    sources_note: 'Planner generated locally in n8n to reduce Gemini free-tier quota usage.'
  }
}];

let plan;

if (Array.isArray($json.search_queries) && Array.isArray($json.outline)) {
  plan = $json;
} else {
  const raw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    plan = JSON.parse(raw);
  } catch {
    plan = {
      search_queries: [],
      angle: 'Practical breakdown with real implementation notes',
      outline: [
        { section: 'Introduction', bullets: ['Context and problem statement'] },
        { section: 'Core Workflow', bullets: ['Step-by-step implementation details'] },
        { section: 'Conclusion', bullets: ['Actionable next steps'] }
      ],
      sources_note: 'No external sources parsed from planner output.'
    };
  }
}

return [{ json: { ...$item(0).$node['Normalize Input'].json, plan } }];

const topic = $json.topic;
const audience = $json.audience;
const tone = $json.tone;
const cta = $json.cta;
const plan = $json.plan ?? {};
const outline = Array.isArray(plan.outline) ? plan.outline : [];
const queries = Array.isArray(plan.search_queries) ? plan.search_queries : [];

const title = `# ${topic}`;
const intro = [
  `${topic} is becoming a practical way for teams to build repeatable automation with better decision-making, context handling, and execution quality.`,
  `This guide is written for ${audience} and takes a ${tone.toLowerCase()} approach so you can move from concept to implementation without losing sight of reliability.`
].join(' ');

const sectionMarkdown = outline.map((item, index) => {
  const sectionTitle = item?.section ? String(item.section) : `Section ${index + 1}`;
  const bullets = Array.isArray(item?.bullets) ? item.bullets : [];
  const explanation = bullets.length
    ? bullets.map((bullet) => `- ${String(bullet)}`).join('\n')
    : '- Add practical implementation notes here.';

  return [
    `## ${sectionTitle}`,
    `In this part of the workflow, focus on the concrete implementation details that help a team move from planning to execution around ${topic}.`,
    explanation
  ].join('\n\n');
}).join('\n\n');

const exampleSection = [
  '## Example Workflow',
  `A simple production-ready starting point is to accept a topic, normalize the request, create a plan, draft the article, derive metadata, and return a structured payload to the frontend.`,
  '- Validate the incoming payload early.',
  '- Keep generation steps observable and deterministic where possible.',
  '- Return both markdown content and structured metadata to the UI.'
].join('\n\n');

const faqSection = [
  '## FAQ',
  '### How should teams start?',
  'Start with a narrow workflow, measure output quality, and improve one step at a time.',
  '### What usually breaks first?',
  'Quota limits, brittle prompts, and missing validation are the first issues most teams encounter.',
  '### How do you make it reliable?',
  'Use strong input normalization, explicit output structures, retries only where appropriate, and clear fallbacks.'
].join('\n\n');

const nextSteps = [
  '## Next Steps',
  `${cta}`,
  queries.length ? `Suggested related search angles: ${queries.join(', ')}.` : ''
].filter(Boolean).join('\n\n');

const draftMarkdown = [
  title,
  intro,
  sectionMarkdown,
  exampleSection,
  faqSection,
  nextSteps
].filter(Boolean).join('\n\n');

return [{ json: { ...$json, draftMarkdown } }];

const draftMarkdown = typeof $json.draftMarkdown === 'string'
  ? $json.draftMarkdown
  : ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('');
if (!draftMarkdown.trim()) {
  throw new Error('Writer step returned empty content');
}

return [{
  json: {
    ...$item(0).$node['Parse Plan'].json,
    draftMarkdown
  }
}];

const source = $item(0).$node['Collect Draft'].json;
const topic = source.topic ?? 'Untitled';
const draftMarkdown = source.draftMarkdown ?? '';

const lines = draftMarkdown
  .split('\n')
  .map((line) => line.trim())
  .filter(Boolean);

const firstHeading = lines.find((line) => line.startsWith('# '));
const title = (firstHeading ? firstHeading.replace(/^#\s+/, '') : topic).trim();
const plainText = draftMarkdown
  .replace(/^#+\s+/gm, '')
  .replace(/```[\s\S]*?```/g, ' ')
  .replace(/`([^`]+)`/g, '$1')
  .replace(/[\*_>#-]/g, ' ')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1')
  .replace(/\s+/g, ' ')
  .trim();

const excerpt = plainText.slice(0, 180).trim() || `Deep dive on ${topic}`;
const metaDescription = plainText.slice(0, 155).trim() || `Technical guide about ${topic}`;
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

const keywords = Array.from(new Set([
  topic,
  ...(Array.isArray(source.plan?.search_queries) ? source.plan.search_queries.slice(0, 4) : []),
  'agentic ai',
  'workflow automation'
].map((item) => String(item).trim()).filter(Boolean)));

return [{
  json: {
    title,
    slug,
    excerpt,
    metaDescription,
    keywords
  }
}];

let seo;

if ($json.title || $json.slug || $json.metaDescription) {
  seo = $json;
} else {
  const seoRaw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    seo = JSON.parse(seoRaw);
  } catch {
    seo = {};
  }
}

const source = $item(0).$node['Collect Draft'].json;
const finalTitle = seo.title || source.topic;
const finalSlug = (seo.slug || source.topic)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

return [{
  json: {
    success: true,
    generatedAt: new Date().toISOString(),
    title: finalTitle,
    slug: finalSlug,
    excerpt: seo.excerpt || `Deep dive on ${source.topic}`,
    metaDescription: seo.metaDescription || `Technical guide about ${source.topic}`,
    keywords: Array.isArray(seo.keywords) ? seo.keywords : [source.topic, 'agentic ai', 'workflow automation'],
    contentMarkdown: source.draftMarkdown,
    plan: source.plan,
    input: {
      topic: source.topic,
      audience: source.audience,
      tone: source.tone,
      wordCount: source.wordCount,
      cta: source.cta
    }
  }
}];
